```

##### Phase 2: 完善前端 WebSocket 客户端

**文件**: `dashboard/src/stores/websocket.ts`

需要添加的功能：
```typescript
class WebSocketStore {
  // 1. 事件类型映射表
  private eventHandlers: Map<string, Function[]> = new Map()

  // 2. 心跳检测
  private heartbeatInterval: any
  private heartbeatTimeout: any

  // 3. 自动重连
  private reconnectAttempts: number = 0
  private maxReconnectAttempts: number = 5
  private reconnectDelay: number = 3000

  // 4. 实现心跳
  startHeartbeat() {
    this.heartbeatInterval = setInterval(() => {
      this.send({ type: 'ping' })
      this.heartbeatTimeout = setTimeout(() => {
        console.warn('Heartbeat timeout, reconnecting...')
        this.reconnect()
      }, 5000)
    }, 30000)
  }

  // 5. 实现自动重连
  private reconnect() {
    if (this.reconnectAttempts < this.maxReconnectAttempts) {
      this.reconnectAttempts++
      setTimeout(() => {
        console.log(`Reconnecting... (${this.reconnectAttempts}/${this.maxReconnectAttempts})`)
        this.connect()
      }, this.reconnectDelay * this.reconnectAttempts)
    }
  }

  // 6. 事件订阅
  on(event: string, handler: Function) {
    if (!this.eventHandlers.has(event)) {
      this.eventHandlers.set(event, [])
    }
    this.eventHandlers.get(event)!.push(handler)
  }

  // 7. 事件分发
  private dispatchEvent(event: string, data: any) {
    const handlers = this.eventHandlers.get(event) || []
    handlers.forEach(handler => handler(data))
  }
}
```

##### Phase 3: 集成 AutoIterationEngine 与 Dashboard

**文件**: `src/auto-iteration.ts`

在迭代过程中实时推送状态：
```typescript
export class AutoIterationEngine {
  async runIteration() {
    // 迭代开始
    await realtimeService.broadcastIterationStatus({
      iterationNumber: this.count,
      status: 'running',
      requirement: this.requirement
    })

    // 产品经理 Agent
    this.updateProgress('product_manager', 10, '分析需求中...')
    const pmResult = await this.productManagerAgent.execute(requirement)
    await realtimeService.broadcastAgentStatus({
      name: 'product_manager',
      status: 'completed',
      result: pmResult
    })

    // 架构师 Agent
    this.updateProgress('architect', 30, '设计系统架构中...')
    const architectResult = await this.architectAgent.execute(pmResult)
    await realtimeService.broadcastAgentStatus({
      name: 'architect',
      status: 'completed',
      result: architectResult
    })

    // ... 其他 Agents
  }

  private updateProgress(agent: string, progress: number, message: string) {
    realtimeService.broadcastIterationProgress({
      agent,
      progress,
      message,
      timestamp: new Date()
    })
  }
}
```

##### Phase 4: 前端实时数据展示

**文件**: `dashboard/src/views/Dashboard.vue`

实现实时更新：
```vue
