  wsStore.on('iteration.status_changed', (data) => {
    console.log('Iteration status changed:', data)
    // 更新 UI
  })

  // 订阅迭代进度
  wsStore.on('iteration.progress', (data) => {
    console.log('Iteration progress:', data)
    // 更新进度条
    currentProgress.value = data.progress
    progressMessage.value = data.message
  })

  // 订阅 Agent 状态
  wsStore.on('agent.status_changed', (data) => {
    console.log('Agent status changed:', data)
    // 更新 Agent 状态卡片
    updateAgentCard(data)
  })

  // 订阅系统指标
  wsStore.on('system.metrics', (data) => {
    console.log('System metrics:', data)
    // 更新图表
    updateCharts(data)
  })

  // 订阅实时日志
  wsStore.on('log.entry', (data) => {
    console.log('Log entry:', data)
    // 添加到日志查看器
    addLogEntry(data)
